INSERT INTO `prompt_technique` (`technique_id`, `technique_name`, `system_prompt_file`, `user_prompt_file`, `prompt_version`, `description`, `created_at`) VALUES
(1, 'zero-shot', 'prompts/zero_shot_system.txt', 'prompts/zero_shot_user.txt', '1.0', 'Zero-shot prompting provides the model with task instructions and output format requirements only, without any examples. The model relies entirely on its pretrained knowledge to extract nutritional information from EN-MS code-switched cooking transcripts.', '2026-06-21 17:26:09'),
(2, 'few-shot', 'prompts/few_shot_system.txt', 'prompts/few_shot_user.txt', '1.0', 'Few-shot prompting supplies the model with a small number of annotated input-output examples before the target transcript. This guides the model toward the expected JSON output structure and handling of informal Malay culinary expressions.', '2026-06-21 17:26:09'),
(3, 'chain-of-thought', 'prompts/chain_of_thought_system.txt', 'prompts/chain_of_thought_user.txt', '1.0', 'Chain-of-thought prompting instructs the model to reason step-by-step before producing the final JSON output. This encourages explicit intermediate reasoning over ingredient identification, quantity interpretation, and language tagging in code-switched text.', '2026-06-21 17:26:09'),
(4, 'structured-output', 'prompts/structured_output_system.txt', 'prompts/structured_output_user.txt', '1.0', 'Structured-output prompting enforces a strict JSON schema in the prompt instructions, constraining the model response to a predefined format. This reduces hallucination risk and improves consistency of the extracted nutritional fields across all five LLMs.', '2026-06-21 17:26:09');
